SourceCode.Declaration:
/// <summary>
/// Extension of the <c>InventTransIdReturn</c> field in the <c>SalesLine</c> data source of the <c>SalesTable</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataFieldStr(SalesTable, SalesLine, InventTransIdReturn))]
final class SalesTable_SalesLine_InventTransIdReturn_ETGSPAIN_FormDataSourceField_Extension
{
}

Method.Source:
/// <summary>
/// Modified method to update unsold inventory transactions when the field changes.
/// </summary>
void modified()
{
    next modified();

    FormDataObject  formDataObject  = any2Object(this) as FormDataObject;
    FormDataSource  formDataSource  = formDataObject.datasource();
    SalesLine       salesLine       = formDataSource.cursor();

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (salesLine.InventTransIdReturn && salesLine.SalesQty)
        {
            ETGSPAINUnsoldInventTrans unsoldInventTrans = ETGSPAINUnsoldInventTrans::findByInventTransId(salesLine.InventTransIdReturn, true);

            if (unsoldInventTrans)
            {
                ETGSPAINUnsoldInventTransModifyController::updateQty(unsoldInventTrans, abs(salesLine.SalesQty));
            }
        }
    }
}
